mapper.select:
SELECT agg.job_group, agg.job_id, info.job_desc, info.author, info.job_tag, agg.failure_count, agg.last_failure_time, last_log.id AS last_log_id, last_log.trigger_code AS last_trigger_code, last_log.handle_code AS last_handle_code, last_log.trigger_msg AS last_trigger_msg, last_log.handle_msg AS last_handle_msg FROM ( SELECT t.job_group, t.job_id, COUNT(1) AS failure_count, MAX(t.trigger_time) AS last_failure_time, MAX(t.id) AS last_log_id FROM xxl_job_log t INNER JOIN xxl_job_info info ON info.id = t.job_id
AND ( t.trigger_code NOT IN (0, 200) OR t.handle_code NOT IN (0, 200) )
AND t.job_group IN
#{item}
AND t.job_group = #{jobGroup}
AND t.job_id = #{jobId}
AND info.author like CONCAT(CONCAT('%', #{author}), '%')
AND info.job_tag like CONCAT(CONCAT('%', #{jobTag}), '%')
AND t.trigger_time >= #{triggerTimeStart}
AND t.trigger_time <= #{triggerTimeEnd}
GROUP BY t.job_group, t.job_id ) agg INNER JOIN xxl_job_info info ON info.id = agg.job_id INNER JOIN xxl_job_log last_log ON last_log.id = agg.last_log_id ORDER BY agg.last_failure_time DESC, agg.failure_count DESC LIMIT #{offset}, #{pagesize}

SELECT COUNT(1)
FROM (
	SELECT
		t.job_group,
		t.job_id
	FROM xxl_job_log t
	INNER JOIN xxl_job_info info ON info.id = t.job_id

		AND (
			t.trigger_code NOT IN (0, 200)
			OR t.handle_code NOT IN (0, 200)
		)

			AND t.job_group IN

				#{item}



			AND t.job_group = #{jobGroup}


			AND t.job_id = #{jobId}


			AND info.author like CONCAT(CONCAT('%', #{author}), '%')


			AND info.job_tag like CONCAT(CONCAT('%', #{jobTag}), '%')


			AND t.trigger_time  >=  #{triggerTimeStart}


			AND t.trigger_time  <=  #{triggerTimeEnd}


	GROUP BY t.job_group, t.job_id
) agg
